{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires calculating the Rydberg energy for a specific exciton state based on the provided binding energy of the 1s state. This involves determining the effective Rydberg constant first.",
  "helpers": [
    {
      "label": "helper_1",
      "instructions": "Extract the band gap (3 eV) and the 1s exciton peak energy (1 eV). Use these to determine the exciton binding energy (E_b = Band Gap - Peak Energy). From the binding energy of the 1s state, calculate the effective Rydberg constant (R_eff) using the formula E_b = R_eff / n^2 where n=1."
    },
    {
      "label": "helper_2",
      "instructions": "Using the effective Rydberg constant (R_eff) calculated in the previous step, calculate the Rydberg energy for the n = 3 state using the formula E_n = -R_eff / n^2. Ensure the final value includes the correct negative sign to represent a bound state energy relative to the conduction band edge."
    }
  ],
  "synthesis_brief": "Combine the effective Rydberg constant from helper 1 with the n=3 state formula in helper 2 to provide the final signed energy value."
}

